#[odra::module]
pub struct MilestoneEscrow {
    payer: Var<Address>,
    recipient: Var<Address>,
    deadline: Var<u64>,
    approved: Var<bool>,
}

#[odra::module]
impl MilestoneEscrow {
    pub fn approve_milestone(&mut self) {
        self.assert_payer();
        self.approved.set(true);
    }

    pub fn release(&mut self) {
        if !self.approved.get_or_default() {
            self.env().revert(Error::NotApproved);
        }
        // Transfer held funds to the recipient.
    }

    pub fn refund_after_timeout(&mut self) {
        if self.env().get_block_time() <= self.deadline.get().unwrap() {
            self.env().revert(Error::DeadlineActive);
        }
        // Return held funds to the payer.
    }
}
